func FindCompletedJobByCacheKey(ctx context.Context, jobStore store.JobStore, cacheKey string) (*types.Job, error) {
	if cacheKey == "" {
		return nil, nil
	}
	if finder, ok := jobStore.(store.CompletedCacheKeyLookup); ok {
		job, err := finder.FindCompletedJobByCacheKey(ctx, cacheKey)
		if errors.Is(err, store.ErrNotFound) {
			return nil, nil
		}
		if err != nil {
			return nil, err
		}
		candidate := job
		return &candidate, nil
	}
	jobs, err := jobStore.ListJobs(ctx)
	if err != nil {
		return nil, err
	}
	for _, job := range jobs {
		if job.CacheKey == cacheKey && job.State == types.JobStateSucceeded && job.Result != nil {
			candidate := job
			return &candidate, nil
		}
	}
	return nil, nil
}

func ValidateSubmitRequest(req types.SubmitJobRequest) error {
	if req.TaskType != "inspect_repo" {
		return nil
	}
	if req.OutputSchema.Name != "repo_inspection_v2" {
		return fmt.Errorf("inspect_repo output_schema.name must be repo_inspection_v2")
	}
	query, _ := req.TaskParams["query"].(string)
	if strings.TrimSpace(query) == "" {
		return fmt.Errorf("inspect_repo query is required")
	}
	if len(query) > MaxInspectRepoQueryBytes {
		return fmt.Errorf("inspect_repo query cannot exceed %d UTF-8 bytes", MaxInspectRepoQueryBytes)
	}
	mode := "auto"
	if value, ok := req.TaskParams["mode"].(string); ok && strings.TrimSpace(value) != "" {
		mode = strings.ToLower(strings.TrimSpace(value))
	}
	switch mode {
	case "auto", "evidence", "answer":
	default:
		return fmt.Errorf("inspect_repo mode must be one of auto, evidence, or answer")
	}
	for key := range req.TaskParams {
		normalized := strings.ToLower(strings.TrimSpace(key))
		if strings.HasPrefix(normalized, "gpu_service") || normalized == "gpu_services" ||
			normalized == "service_endpoints" || normalized == "endpoint_selections" ||
			normalized == "runtime_services" || normalized == "service_selection" ||
			normalized == "index_cache_dir" || normalized == "repo_inspection_cache_path" {
			return fmt.Errorf("inspect_repo task parameter %q is broker-reserved", key)
		}
	}
	for name, value := range map[string]int{
		"retrieval_token_budget":         req.Constraints.RetrievalTokenBudget,
		"evidence_token_budget":          req.Constraints.EvidenceTokenBudget,
		"final_pack_token_budget":        req.Constraints.FinalPackTokenBudget,
		"synthesis_context_token_budget": req.Constraints.SynthesisContextTokenBudget,
	} {
		if value < 0 {
			return fmt.Errorf("inspect_repo %s must be non-negative", name)
		}
	}
	finalPackBudget := req.Constraints.FinalPackTokenBudget
	if finalPackBudget == 0 {
		finalPackBudget = req.Constraints.FinalEvidencePackBudget
	}
	if finalPackBudget > 0 && finalPackBudget < MinInspectRepoFinalPackTokens {
		return fmt.Errorf("inspect_repo final_pack_token_budget must be at least %d tokens when set", MinInspectRepoFinalPackTokens)
	}
	return nil
}

def _load_cache(self, key, *, _seen=None):
    _seen = set(_seen or ())
    if key in _seen:
        return None
    _seen.add(key)
    path = self._cache_path(key)
    alias_path = self._cache_alias_path(key)
    if path is None:
        return None
    if not path.exists():
        if alias_path is None or not alias_path.exists():
            return None
        try:
            payload = json.loads(alias_path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError, TypeError, ValueError):
            alias_path.unlink(missing_ok=True)
            return None
        if not isinstance(payload, dict) or payload.get("schema") != "gpu_semantic_index_alias_v1":
            alias_path.unlink(missing_ok=True)
            return None
        source = payload.get("source") or {}
        source_key = (
            str(source.get("model_profile") or ""),
            str(source.get("index_fingerprint") or ""),
        )
        if not source_key[1]:
            alias_path.unlink(missing_ok=True)
            return None
        loaded = self._load_cache(source_key, _seen=_seen)
        if loaded is None:
            alias_path.unlink(missing_ok=True)
            return None
        normalized = {
            "ready": bool(loaded.get("ready")),
            "model": str(loaded.get("model") or ""),
            "documents": [dict(document) for document in (loaded.get("documents") or ())],
        }
        self._invalidate_search_state(normalized)
        search_index = self._load_faiss_cache(source_key)
        if search_index is not None:
            normalized["_search_index"] = search_index
            normalized["_search_ids"] = [str(document.get("id") or "") for document in normalized["documents"]]
        return normalized
    try:
        with gzip.open(path, "rt", encoding="utf-8") as handle:
            payload = json.load(handle)
    except (OSError, json.JSONDecodeError, TypeError, ValueError):
        with contextlib.suppress(OSError):
            path.unlink()
        return None
    if not isinstance(payload, dict) or payload.get("schema") not in {"gpu_semantic_index_v1", "gpu_semantic_index_v2"}:
        return None
    record = payload.get("record")
    cache_key = payload.get("key") or {}
    schema = str(payload.get("schema") or "")
    if (
        not isinstance(record, dict)
        or str(cache_key.get("model_profile") or "") != key[0]
        or str(cache_key.get("index_fingerprint") or "") != key[1]
    ):
        return None
    documents = record.get("documents")
    if not isinstance(documents, list):
        return None
    normalized = {"ready": bool(record.get("ready")), "model": str(record.get("model") or ""), "documents": []}
    for document in documents:
        if not isinstance(document, dict):
            return None
        identifier = str(document.get("id") or "")
        vector = document.get("vector")
        if not identifier or not isinstance(vector, list) or not vector:
            return None
        normalized_document = {
            "id": identifier,
            "vector": [float(value) for value in vector],
        }
        if schema == "gpu_semantic_index_v1":
            text = document.get("text")
            if not isinstance(text, str):
                return None
            normalized_document["text"] = text
        normalized["documents"].append(normalized_document)
    self._invalidate_search_state(normalized)
    search_index = self._load_faiss_cache(key)
    if search_index is not None:
        normalized["_search_index"] = search_index
        normalized["_search_ids"] = [str(document.get("id") or "") for document in normalized["documents"]]
    return normalized

func TestFindCompletedJobByCacheKeyPrefersDirectStoreLookup(t *testing.T) {
	now := time.Now().UTC()
	jobStore := &directLookupStore{
		job: types.Job{
			ID:          "job_direct",
			State:       types.JobStateSucceeded,
			CacheKey:    "sha256:direct",
			Result:      &types.Result{SchemaName: "document_summary_v1", Payload: map[string]any{"summary": "ok"}},
			CreatedAt:   now,
			UpdatedAt:   now,
			SubmittedAt: now,
		},
	}

	found, err := FindCompletedJobByCacheKey(context.Background(), jobStore, "sha256:direct")
	if err != nil {
		t.Fatalf("find by cache key: %v", err)
	}
	if found == nil || found.ID != "job_direct" {
		t.Fatalf("expected direct lookup job, got %#v", found)
	}
	if jobStore.directFindCalls != 1 {
		t.Fatalf("expected one direct lookup call, got %d", jobStore.directFindCalls)
	}
	if jobStore.listJobsCalls != 0 {
		t.Fatalf("expected ListJobs to be skipped, got %d calls", jobStore.listJobsCalls)
	}
}

func toolDefinitions() []map[string]any {
	ragSpecs := tasks.RAGAliasSpecs()
	defs := make([]map[string]any, 0, len(ragSpecs)+12)
	for _, spec := range ragSpecs {
		properties := map[string]any{
			"input_refs":           inputRefsSchema(),
			"retrieval_strategies": retrievalStrategiesSchema(),
			"task_params":          map[string]any{"type": "object"},
			"constraints":          ragConstraintsSchema(),
			"execution_profile":    ragExecutionProfileSchema(),
			"idempotency_key":      map[string]any{"type": "string"},
			"wait_for_result":      map[string]any{"type": "boolean"},
			"max_wait_seconds":     map[string]any{"type": "integer"},
			"poll_interval_ms":     map[string]any{"type": "integer"},
		}
		if spec.PromptField != "" {
			properties[spec.PromptField] = map[string]any{"type": "string"}
		}
		if spec.Name == "inspect_repo" {
			properties["query"] = map[string]any{"type": "string", "maxLength": tasks.MaxInspectRepoQueryBytes}
			properties["constraints"] = inspectRepoConstraintsSchema()
			properties["mode"] = map[string]any{
				"type":    "string",
				"enum":    []string{"auto", "evidence", "answer"},
				"default": "auto",
			}
			properties["include_full_trace"] = map[string]any{"type": "boolean", "default": false}
		}
		defs = append(defs, ragToolDefinition(spec.Name, spec.Description, spec.Required, properties))
	}
	for _, spec := range coreToolDefinitions() {
		defs = append(defs, map[string]any{
			"name":        spec.name,
			"description": spec.description,
			"inputSchema": spec.inputSchema,
		})
	}
	return defs
}

func (s *FileJobStore) persistCacheIndexLocked() error {
	index := make(map[string]fileCacheIndexEntry, len(s.completedByCacheKey))
	for cacheKey, jobID := range s.completedByCacheKey {
		job, ok := s.jobs[jobID]
		if !ok || !cacheEligible(job) {
			continue
		}
		schemaName := ""
		qualityResult := ""
		if job.Result != nil {
			schemaName = job.Result.SchemaName
			if quality, ok := job.Result.Payload["quality"].(map[string]any); ok {
				if value, ok := quality["result"].(string); ok {
					qualityResult = value
				}
			}
		}
		index[cacheKey] = fileCacheIndexEntry{
			JobID:         job.ID,
			SubmittedBy:   job.SubmittedBy,
			ArtifactCount: len(job.Artifacts),
			SchemaName:    schemaName,
			QualityResult: qualityResult,
		}
	}
	if cacheIndexEntriesEqual(s.cacheIndexEntries, index) {
		return nil
	}
	data, err := json.Marshal(index)
	if err != nil {
		return err
	}
	tmpFile, err := os.CreateTemp(filepath.Dir(s.cacheIndexPath), "jobs-cache-index-*.tmp")
	if err != nil {
		return err
	}
	tmpPath := tmpFile.Name()
	defer os.Remove(tmpPath)
	if _, err := tmpFile.Write(data); err != nil {
		tmpFile.Close()
		return err
	}
	if err := tmpFile.Close(); err != nil {
		return err
	}
	if err := os.Rename(tmpPath, s.cacheIndexPath); err != nil {
		return err
	}
	s.cacheIndexEntries = index
	if info, err := os.Stat(s.cacheIndexPath); err == nil {
		s.cacheIndexMTimeNs = info.ModTime().UnixNano()
	}
	return nil
}
